UPDATE jobs SET user_contributed_json = '{"way":"주차관리·안내원이 되려면 별도의 국가자격증이 필수는 아니지만,[1] 도로교통 및 주차 관련 법규에 대한 기본 지식이 필요하다. 채용은 주로 주차 용역업체, 대형 쇼핑몰, 공공시설 등에서 이루어지며 경력직을 우대한다.[2] 경비 업무를 병행하는 자리에 지원할 경우 경비원 신임교육(24시간)을 이수하면 일반경비원 자격이 주어져 취업 범위가 넓어진다.[3] 일부 고급 시설에서는 발렛 서비스 담당자에게 1종 운전면허를 요구하기도 하므로, 사전 취득해 두면 유리하다.","overviewSalary":{"sal":"주차관리·안내원의 평균 연봉은 약 2,100만~2,500만 원 수준이며,[1] 고용 형태(정규직·계약직·용역)와 근무 시설 규모에 따라 차이가 크다. 대형 복합시설 소속 정규직의 경우 4대 보험·퇴직금 포함 시 실질 처우가 개선된다.[2]","source":"워크넷 직업정보, 사람인 급여정보(2024)"},"overviewProspect":{"main":"무인 주차 정산기·번호판 인식 시스템 확산으로 단순 안내 인력 수요는 완만히 감소할 전망이다.[1] 다만 병원·공항·복합쇼핑몰 등 고객 서비스 품질이 중요한 대형 시설에서는 유인 안내 인력을 유지하는 경향이 있어 일정 수준의 채용은 지속될 것으로 보인다.[2]","source":"한국고용정보원 직업전망(2024)"},"trivia":"운전면허 없이도 취업 가능한 서비스직 중 하나로, 접수 및 안내 업무 중심의 자리는 면허를 요구하지 않는다.[1] 주차장법 시행규칙에 따라 200면 이상 노외 주차장은 관리사무소 및 안내 인력 배치가 의무화되어 있다.[2] 스마트 주차 시스템이 확산되면서 주차관리 인력의 역할이 단순 유도에서 시스템 모니터링·고객 민원 처리로 이동하고 있다.[3]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"2~3교대 근무로 야간·주말 근무가 빈번하며,[4] 장시간 야외 또는 지하 공간에서 매연과 소음에 노출된다. 명절·연휴에도 정상 근무가 요구되어 여가 시간 확보가 어렵다.","socialDetail":"고객 불만·민원 처리가 잦고 차량 접촉 사고 발생 시 책임 소재로 인한 심리적 부담이 크다.[5] 대부분 단순 반복 업무 위주로 직업 사회적 인정도가 낮은 편이다."},"detailReady":{"curriculum":["도로교통법 및 주차장법 기초 학습","고객 응대 및 서비스 마인드 교육 이수","경비원 신임교육(24시간) 이수로 경비·주차 겸직 자리 지원 가능"],"recruit":["주차 용역 전문업체(파킨손, AJ파크 등) 채용 공고 지원","대형 쇼핑몰·병원·공공기관 시설관리 부서 직접 지원","워크넷·사람인·잡코리아 등 구인 사이트 활용"],"training":["1종 보통 운전면허 취득으로 발렛 파킹 업무 진출","경비지도사 자격 취득으로 관리직 승진 도모","교통안전관리자 자격 취득으로 공공기관 시설 취업 유리"]},"sidebarJobs":["경비원","경호원","청원경찰","환경미화원","전기안전관리원"],"sidebarMajors":["관광경영과","사회복지과","경영학과","경영정보과"],"sidebarCerts":["경비지도사","1종 보통 운전면허","교통안전관리자","주차시설관리사","생활안전지도사"],"heroTags":["주차관리원","주차안내원","주차장 취업","경비원","주차 서비스"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 – 주차관리원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=376"},{"id":2,"text":"워크넷 직업정보 – 주차관리·안내원","url":"https://www.work.go.kr/seekWantedMain.do"},{"id":3,"text":"경비업법 시행령 – 신임교육 규정","url":"https://www.law.go.kr/법령/경비업법시행령"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보 급여 통계(2024)","url":"https://www.work.go.kr/seekWantedMain.do"},{"id":2,"text":"사람인 직종별 급여 리포트(2024)","url":"https://www.saramin.co.kr"}],"overviewProspect.main":[{"id":1,"text":"한국고용정보원 2024 직업전망","url":"https://www.keis.or.kr/user/extra/main/2073/publication/publicationList/jsp/LayOutPage.do"},{"id":2,"text":"스마트 주차 시스템 현황 보고서(2023)","url":"https://www.parking.or.kr"}],"trivia":[{"id":1,"text":"커리어넷 직업백과 – 주차관리원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=376"},{"id":2,"text":"주차장법 시행규칙(국가법령정보센터)","url":"https://www.law.go.kr/법령/주차장법시행규칙"},{"id":3,"text":"스마트파킹 산업 동향(2023)","url":"https://www.parking.or.kr"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=376"}]}}' WHERE id = '1765283485749444';

UPDATE jobs SET user_contributed_json = '{"way":"가구조립원이 되기 위한 별도의 국가자격증은 없으며, 가구 제조업체 생산직 채용 후 현장에서 실무를 습득하는 것이 일반적이다.[1] 한국폴리텍대학이나 직업전문학교의 가구·목공 제조 훈련과정(3~6개월)을 이수하면 보다 체계적인 기술을 익힐 수 있다.[2] 입직 후에는 조립·도장·포장 등 각 공정을 순환하며 숙련도를 높이고, 반장이나 품질 검사원으로 성장하는 경우가 많다.[3] 가구 디자인에 관심이 있다면 산업기사 이상의 가구 관련 자격을 취득해 설계 부서로 이동하는 경로도 있다.","overviewSalary":{"sal":"가구조립원의 평균 연봉은 약 2,600만~3,200만 원 수준이다.[1] 대형 가구 제조업체의 경우 생산 실적에 따른 인센티브가 추가되며, 야간 근무 시 수당이 붙어 실수령액이 높아진다.[2]","source":"워크넷 직업정보, 고용노동부 임금통계(2024)"},"overviewProspect":{"main":"국내 가구 생산 일부가 동남아시아 저임금 국가로 이전하는 추세로 단순 조립직 수요는 완만히 감소할 전망이다.[1] 그러나 맞춤 가구, 친환경 목재 가구 등 고품질 프리미엄 제품 수요는 꾸준해 숙련 기술자에 대한 수요는 안정적으로 유지될 것으로 예상된다.[2]","source":"한국가구산업협동조합, 한국고용정보원(2024)"},"trivia":"국내 가구 시장 규모는 연간 약 6조 원으로, 코로나19 이후 홈퍼니싱 열풍으로 크게 성장했다.[1] 이케아 조립 설명서는 전 세계 공통으로 언어 없이 그림만으로 구성되어 있으며, 이 방식은 국내 DIY 가구 트렌드에도 영향을 미쳤다.[2] 숙련된 가구 조립원이 한 번에 조립 가능한 가구 수는 초보자보다 3~5배 빠르며, 대형 책장 한 조를 10분 내에 완성하기도 한다.[3]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"공장 생산직 특성상 2교대 근무가 일반적이며 야간 근무가 포함된다.[4] 목재 분진, 도료 냄새 등 작업 환경 노출이 있으며 반복 동작으로 인한 근골격계 질환 발생 위험이 존재한다.","socialDetail":"제조업 생산직으로 사회적 인정도는 낮은 편이나,[5] 가구 완성품을 직접 만드는 성취감은 있다. 숙련 기술자는 현장에서 높은 대우를 받는다."},"detailReady":{"curriculum":["한국폴리텍대학 가구디자인과 또는 목공 훈련과정 이수","목공 관련 직업전문학교 단기 과정(3~6개월) 수료","도면 해독 및 가구 설계 기초 학습"],"recruit":["현대리바트, 에넥스, 한샘 등 대형 가구 제조업체 생산직 공채 지원","중소 가구 업체 현장 직접 방문 지원","고용노동부 워크넷을 통한 가구제조업 구인 정보 확인"],"training":["실내건축기능사·목공예기능사 자격 취득으로 설계·가공 부서 이동","가구품질검사원 자격 취득으로 품질관리직 진출","소목장 기능사·기능장 자격 취득으로 전통 목공 분야 진출"]},"sidebarJobs":["가구도장원","가구디자이너","가구수리원","목재가공기계조작원","소목장","인테리어디자이너"],"sidebarMajors":["목조형가구학과","산업디자인과","실내디자인과","공예학과"],"sidebarCerts":["목공예기능사","실내건축기능사","가구품질검사원","소목장기능사","인테리어기능사"],"heroTags":["가구조립원","가구제조","가구공장 취업","목공 직업","생산직 취업"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 – 가구조립원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=339"},{"id":2,"text":"한국폴리텍대학 가구디자인과 안내","url":"https://www.kopo.ac.kr"},{"id":3,"text":"워크넷 직업정보 – 가구조립원","url":"https://www.work.go.kr/seekWantedMain.do"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보 급여 통계(2024)","url":"https://www.work.go.kr/seekWantedMain.do"},{"id":2,"text":"고용노동부 임금통계(2024)","url":"https://laborstat.moel.go.kr"}],"overviewProspect.main":[{"id":1,"text":"한국가구산업협동조합 산업 동향(2023)","url":"https://www.furniture.or.kr"},{"id":2,"text":"한국고용정보원 2024 직업전망","url":"https://www.keis.or.kr/user/extra/main/2073/publication/publicationList/jsp/LayOutPage.do"}],"trivia":[{"id":1,"text":"한국가구산업협동조합 통계(2023)","url":"https://www.furniture.or.kr"},{"id":2,"text":"이케아 조립 설명서 제작 방식 소개","url":"https://www.ikea.com/kr/ko"},{"id":3,"text":"커리어넷 직업백과 – 가구조립원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=339"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=339"}]}}' WHERE id = '1765283527843336';

UPDATE jobs SET user_contributed_json = '{"way":"표백·염색기조작원이 되기 위한 국가자격 요건은 없으며, 섬유·의류 제조업체의 생산직 채용 후 현장 실무를 통해 기술을 익힌다.[1] 일부 업체에서는 입직 전 고용노동부 직업훈련기관의 섬유 가공·염색 훈련과정을 이수한 인력을 선호한다.[2] 작업 중 화학약품(염료, 표백제)을 다루므로 화학물질 취급 안전 교육 이수가 필수이며,[3] 숙련자는 공정 관리자나 품질 검사원으로 성장할 수 있다.","overviewSalary":{"sal":"표백·염색기조작원의 평균 연봉은 약 2,400만~2,900만 원 수준이다.[1] 야간 교대 근무 시 야간·위험 수당이 추가되어 실수령액이 높아지며,[2] 대기업 계열 섬유 공장 소속 정규직은 복리후생 수준이 상대적으로 양호하다.","source":"워크넷 직업정보, 고용노동부 임금통계(2024)"},"overviewProspect":{"main":"국내 섬유 산업의 해외 이전 및 자동화 확대로 단순 기계 조작직 수요는 장기적으로 감소할 전망이다.[1] 다만 친환경 염색, 기능성 섬유 가공 등 고부가가치 분야에서는 숙련 기술자 수요가 유지될 것으로 보인다.[2]","source":"한국섬유산업연합회, 한국고용정보원(2024)"},"trivia":"천연 염색에 사용되는 쪽풀(인디고) 염료는 수천 년의 역사를 가지며, 현대 청바지의 남색도 이 계열의 합성 인디고에서 비롯됐다.[1] 섬유 염색 시 색상 재현성을 높이기 위해 pH, 온도, 시간 등 수십 개의 변수를 정밀하게 제어하는 노하우가 필요하다.[2] 국내 섬유 염색 산업은 경북 구미·대구 지역에 집중되어 있으며, 전국 염색 공장의 절반 이상이 이 지역에 위치한다.[3]","detailWlb":{"wlb":"보통이하","social":"보통이하","wlbDetail":"2~3교대 근무로 야간 작업이 포함되며,[4] 고온다습한 환경과 화학약품 취급으로 인한 건강 위험이 있다. 방진 마스크·방호복 착용이 필수이나 장시간 착용 시 불편하다.","socialDetail":"제조업 생산직 중에서도 작업 강도와 환경 위험도가 높은 편에 속한다.[5] 사회적 인정도는 낮지만 숙련 기술자는 공정 관리자로 성장하며 현장에서 인정받는다."},"detailReady":{"curriculum":["섬유·화학 관련 직업훈련기관 염색 가공 과정 이수","화학물질 취급 안전 교육 및 GHS(화학물질 국제분류) 학습","섬유 재료학 및 염색 화학 기초 학습"],"recruit":["대구·구미 지역 섬유 염색 업체 현장 지원","워크넷·고용24를 통한 섬유가공 구인 정보 확인","한국폴리텍대학 섬유 관련 학과 수료 후 취업 연계"],"training":["염색기능사 자격 취득으로 전문성 향상","섬유가공기사 자격 취득으로 기술직·관리직 진출","위험물 산업기사 자격 취득으로 화학약품 관리 업무 확장"]},"sidebarJobs":["세탁기계조작원","의류수선원","의복수선원","편물원"],"sidebarMajors":["섬유공학과","화학공학과","고분자공학과","의류·의상학과"],"sidebarCerts":["염색기능사","섬유가공기사","위험물산업기사","화학분석기능사","품질경영기사"],"heroTags":["염색기조작원","표백기조작원","섬유공장 취업","염색 직업","섬유가공"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과 – 염색·표백기조작원","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=348"},{"id":2,"text":"한국폴리텍대학 섬유관련 훈련과정","url":"https://www.kopo.ac.kr"},{"id":3,"text":"화학물질관리법 – 취급 안전 교육 규정","url":"https://www.law.go.kr/법령/화학물질관리법"}],"overviewSalary.sal":[{"id":1,"text":"워크넷 직업정보 급여 통계(2024)","url":"https://www.work.go.kr/seekWantedMain.do"},{"id":2,"text":"고용노동부 임금통계(2024)","url":"https://laborstat.moel.go.kr"}],"overviewProspect.main":[{"id":1,"text":"한국섬유산업연합회 통계(2023)","url":"https://www.kofoti.or.kr"},{"id":2,"text":"한국고용정보원 2024 직업전망","url":"https://www.keis.or.kr/user/extra/main/2073/publication/publicationList/jsp/LayOutPage.do"}],"trivia":[{"id":1,"text":"섬유염색역사 – 한국섬유산업연합회","url":"https://www.kofoti.or.kr"},{"id":2,"text":"염색공정 변수 제어 기술 – 커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=348"},{"id":3,"text":"대구경북 섬유산업 클러스터 현황(2023)","url":"https://www.dgtp.or.kr"}],"detailWlb.wlbDetail":[{"id":4,"text":"워크넷 직업정보 – 근무환경","url":"https://www.work.go.kr/seekWantedMain.do"}],"detailWlb.socialDetail":[{"id":5,"text":"커리어넷 직업백과 – 직업 만족도","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do?SEQ=348"}]}}' WHERE id = '1765283518939219';